"use client"; import { useState } from "react"; import AuthGuard from "@/components/AuthGuard"; import PageHeader from "@/components/PageHeader"; import DashboardShell from "@/components/DashboardShell"; import { userApi } from "@/lib/api"; export default function SettingsPage() { const [currentPassword, setCurrentPassword] = useState(""); const [newPassword, setNewPassword] = useState(""); const [msg, setMsg] = useState(""); const [error, setError] = useState(""); const submit = async () => { setMsg(""); setError(""); try { await userApi.changePassword({ currentPassword, newPassword }); setMsg("Password changed"); } catch (e:any) { setError(e.message); } }; return <AuthGuard><PageHeader title="Settings" text="Change account password and manage personal preferences." /><DashboardShell><div className="card card-pad">{msg && <div className="notice notice-ok">{msg}</div>}{error && <div className="notice notice-error">{error}</div>}<div className="grid" style={{ maxWidth: 540 }}><input className="input" type="password" placeholder="Current password" value={currentPassword} onChange={e=>setCurrentPassword(e.target.value)} /><input className="input" type="password" placeholder="New password" value={newPassword} onChange={e=>setNewPassword(e.target.value)} /><button className="btn btn-primary" onClick={submit}>Update password</button></div></div></DashboardShell></AuthGuard>; }
